create table api_keys (active boolean not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, key_hash varchar(255) not null unique, key_prefix varchar(255) not null, mode varchar(255) not null, primary key (id));
create table applications (created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, organization_id uuid not null, name varchar(255) not null, primary key (id));
create table assets (active boolean not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, asset_type varchar(255) not null check (asset_type in ('INTEGER','DECIMAL','BOOLEAN','STRING','TIME_BASED','CUSTOM')), default_value varchar(255), delivery_method varchar(255), description text, display_color varchar(255), display_icon varchar(255), internal_key varchar(255) not null, max_value varchar(255), name varchar(255) not null, metadata jsonb, primary key (id), unique (merchant_id, internal_key));
create table coupons (active boolean not null, discount_value numeric(38,2) not null, max_uses integer, times_used integer not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, valid_until timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, code varchar(255) not null unique, discount_type varchar(255) not null check (discount_type in ('PERCENTAGE','FIXED')), primary key (id));
create table customers (total_spent numeric(38,2) not null, join_date timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, email varchar(255) not null, name varchar(255), status varchar(255) not null, primary key (id));
create table invoices (currency varchar(3) not null, total_amount numeric(38,2) not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, order_id uuid, customer_email varchar(255) not null, invoice_number varchar(255) not null unique, status varchar(255) not null check (status in ('DRAFT','OPEN','PAID','UNCOLLECTIBLE','VOID')), primary key (id));
create table merchants (created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, email varchar(255) not null unique, password_hash varchar(255) not null, metadata jsonb, primary key (id));
create table order_line_items (quantity integer not null, subtotal numeric(38,2) not null, unit_price numeric(38,2) not null, id uuid not null, order_id uuid not null, product_id uuid not null, primary key (id));
create table orders (currency varchar(3) not null, total_amount numeric(38,2) not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, customer_email varchar(255), order_reference varchar(255) not null unique, payment_link varchar(255), status varchar(255) not null check (status in ('CREATED','PENDING','PAID','FAILED','REFUNDED')), primary key (id));
create table organizations (created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, name varchar(255) not null, primary key (id));
create table payment_intents (amount numeric(38,2) not null, currency varchar(3) not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, order_id uuid not null, error_message varchar(255), gateway_provider varchar(255) not null, gateway_reference varchar(255), status varchar(255) not null check (status in ('INITIATED','AUTHORIZED','CAPTURED','FAILED','REFUNDED')), primary key (id));
create table product_asset_links (quantity_granted integer not null, created_at timestamp(6) with time zone, asset_id uuid not null, id uuid not null, product_id uuid not null, primary key (id));
create table products (active boolean not null, base_credits integer, bonus_credits integer, currency varchar(3) not null, grace_period_days integer, price numeric(38,2) not null, purchase_limit integer, trial_period_days integer, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, billing_cycle varchar(255) check (billing_cycle in ('DAILY','WEEKLY','MONTHLY','QUARTERLY','YEARLY','LIFETIME')), description text, display_image varchar(255), hosted_checkout_url varchar(255), name varchar(255) not null, product_type varchar(255) not null check (product_type in ('SUBSCRIPTION','CREDIT_PACK','BUNDLE','ONE_TIME')), visibility varchar(255) not null check (visibility in ('PUBLIC','PRIVATE','UNLISTED')), benefits jsonb, cancellation_rules jsonb, metadata jsonb, renewal_rules jsonb, primary key (id));
create table subscriptions (cancel_at_period_end boolean, created_at timestamp(6) with time zone, current_period_end timestamp(6) with time zone, current_period_start timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, product_id uuid not null, customer_email varchar(255) not null, status varchar(255) not null check (status in ('INCOMPLETE','ACTIVE','PAST_DUE','CANCELED')), primary key (id));
create table webhook_endpoints (active boolean not null, created_at timestamp(6) with time zone, updated_at timestamp(6) with time zone, id uuid not null, merchant_id uuid not null, secret_key varchar(255) not null, url varchar(255) not null, primary key (id));
alter table if exists order_line_items add constraint FKdjnh2emxm9tt6mrpfabdvbs0c foreign key (order_id) references orders;
alter table if exists product_asset_links add constraint FKcld10r1r6mblsj6ibl4qn4ik4 foreign key (asset_id) references assets;
alter table if exists product_asset_links add constraint FK1s7anprs6tpxj24lhux7dy9ui foreign key (product_id) references products;
